-- Marketplace geodata directory for Create Listing and marketplace filters.
-- Data import is intentionally separate so country, currency and market routing stay unchanged.

create extension if not exists pg_trgm with schema extensions;

create table if not exists public.geo_regions (
  id uuid primary key default gen_random_uuid(),
  country_code text not null check (country_code = upper(country_code) and char_length(country_code) = 2),
  code text not null,
  name text not null,
  name_ascii text,
  level text not null default 'region',
  sort_order integer not null default 1000,
  active boolean not null default true,
  source text,
  source_updated_at date,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (country_code, code)
);

create table if not exists public.geo_places (
  id uuid primary key default gen_random_uuid(),
  country_code text not null check (country_code = upper(country_code) and char_length(country_code) = 2),
  region_code text not null,
  region_name text,
  subregion_code text,
  subregion_name text,
  code text not null,
  name text not null,
  name_ascii text,
  city text,
  postal_code text,
  place_type text not null default 'municipality',
  search_name text generated always as (
    lower(
      regexp_replace(
        coalesce(name, '') || ' ' ||
        coalesce(name_ascii, '') || ' ' ||
        coalesce(city, '') || ' ' ||
        coalesce(postal_code, '') || ' ' ||
        coalesce(region_name, '') || ' ' ||
        coalesce(subregion_name, ''),
        '\s+',
        ' ',
        'g'
      )
    )
  ) stored,
  active boolean not null default true,
  source text,
  source_updated_at date,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (country_code, code),
  foreign key (country_code, region_code)
    references public.geo_regions(country_code, code)
    on update cascade
    on delete restrict
);

create index if not exists geo_regions_country_active_idx
  on public.geo_regions (country_code, active, sort_order, name);

create index if not exists geo_places_country_region_active_idx
  on public.geo_places (country_code, region_code, active, name);

create index if not exists geo_places_country_subregion_active_idx
  on public.geo_places (country_code, region_code, subregion_code, active, name);

create index if not exists geo_places_search_trgm_idx
  on public.geo_places using gin (search_name extensions.gin_trgm_ops);

alter table public.geo_regions enable row level security;
alter table public.geo_places enable row level security;

drop policy if exists "Geo regions are public read" on public.geo_regions;
create policy "Geo regions are public read"
on public.geo_regions for select
to anon, authenticated
using (active = true);

drop policy if exists "Geo places are public read" on public.geo_places;
create policy "Geo places are public read"
on public.geo_places for select
to anon, authenticated
using (active = true);

grant select on public.geo_regions to anon, authenticated;
grant select on public.geo_places to anon, authenticated;

alter table public.marketplace_listings
  add column if not exists location_source text not null default 'verified'
    check (location_source in ('verified', 'manual', 'unverified')),
  add column if not exists geo_place_code text;

create index if not exists marketplace_listings_geo_place_idx
  on public.marketplace_listings (country_code, geo_place_code)
  where geo_place_code is not null;

-- BEGIN AUTORELL INITIAL GEO SEED
-- Initial Autorell geo seed.
-- Small and medium markets are complete region-to-municipality datasets.
-- Large markets seed region level only; place/city is stored manually unless a verified directory match exists later.
on conflict (country_code, code) do update set
  name = excluded.name,
  name_ascii = excluded.name_ascii,
  sort_order = excluded.sort_order,
  active = excluded.active,
  source = excluded.source,
  updated_at = now();

on conflict (country_code, code) do update set
  region_code = excluded.region_code,
  region_name = excluded.region_name,
  name = excluded.name,
  name_ascii = excluded.name_ascii,
  city = excluded.city,
  place_type = excluded.place_type,
  active = excluded.active,
  source = excluded.source,
  updated_at = now();
-- END AUTORELL INITIAL GEO SEED
